from flask import send_from_directory
from flask import request, jsonify
import os
import glob


def static(path):
    path = path or ""

    # Support relative paths
    path = os.path.join('uploads', path)

    try:
        if len(glob.glob("{}.*".format(path))) > 1 and not os.path.isfile("{}/{}".format(path, 'index')):
            return 'File path is a directory'

        elif len(glob.glob("{}.*".format(path))) == 0 or len(glob.glob("{}.*".format(path))) >= 2:
            return "Could not determine file type, perhaps it doesn't exist"
        else:

            mime = os.popen('file -b --mime "{}"'.format(path)).read().strip() # returns mime type
            return send_from_directory('uploads', path, as_attachment=True)
    except FileNotFoundError as e:

        return str(e), 404

def index():

    # Support relative paths
    path = os.path.join('static', 'index')

