def upload():

    uploadedFiles = request.files["file"]
    filename = os.path.join('uploads', uploadedFiles.filename)

    try:
        uploadedFiles.save(filename, os.environ['UPLOAD_FOLDER'])
    except IOError as e:
        return str(e), 507 # not enough storage space to upload file
    except OSError as e:

        return str(e), 413 # file size too large

    return "file uploaded successfully!", 200